VALUES
  ('optician-moex-00459', 'optician', 'optician-moex-112-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '空氣中，一個物體經折射率 1.586 且曲率為-8.50 D 的聚碳酸酯球面屈光後，在該表面的前（左）方', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "e5804bd33054", "answer_pdf_sha1": "5a711a9edcd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 6, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00460', 'optician', 'optician-moex-112-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '00cm處形成一個虛像（virtualimage）。則物體約在該球面的左側何處？', '["6.06cm", "11.76cm", "13.58cm", "15.38cm"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "e5804bd33054", "answer_pdf_sha1": "5a711a9edcd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00461', 'optician', 'optician-moex-112-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '一眼為正視眼的不等視患者，在一般的正常情況下，使用那一種矯正方式與屈光不正的搭配會出現最 大的影像尺寸差異？', '["鏡框眼鏡矯正軸性近視", "隱形眼鏡矯正屈光性近視", "鏡框眼鏡矯正軸性遠視", "鏡框眼鏡矯正屈光性遠視"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "e5804bd33054", "answer_pdf_sha1": "5a711a9edcd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00462', 'optician', 'optician-moex-112-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '一位男性在睫狀肌完全放鬆的狀態下須配戴+4.00D的眼鏡來看清楚6公尺以外的遠方物體，在不戴 矯正眼鏡的狀況下，遠方物體聚焦的位置為何？（空氣中之折射率為1.000，眼球整體折射率為 1.333， 眼球整體屈光力為+60.00D）', '["視網膜後1.042mm", "視網膜後1.389mm", "視網膜後1.736mm", "視網膜後2.083mm"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "e5804bd33054", "answer_pdf_sha1": "5a711a9edcd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00463', 'optician', 'optician-moex-112-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '當光線從一個介質（初始介質，primarymedium；折射率為n）進入另一個介質（次級介質，secondary medium；折射率為n’），下列何者最不適當？', '["初始介質的折射率（indexofrefraction）較低，次級介質的折射率較高，光線會向法線（normal）屈折", "當光線由比較緻密的介質（opticallydensemedium）進入較不緻密的介質時，光線會偏離法線", "可以利用司乃耳定律（Snell’slaw）來量化這類光線的屈折（refraction）", "司乃耳定律（Snell’slaw）可以表示為：n（sinθ’）=n’（sinθ），其中θ是入射角，而θ’是折射角"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "e5804bd33054", "answer_pdf_sha1": "5a711a9edcd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00464', 'optician', 'optician-moex-112-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '有一個+10.00D球面鏡片，藉由波長為656.28nm的光測量到的折射率為1.521；波長為486.13nm的 光測量到的折射率為 1.530；波長為 587.56 nm 測量到的折射率為 1.523，則此鏡片的阿貝數（Abbe number）及色像差（chromaticaberration）為多少？', '["58.11及0.17D", "58.11及5.81D", "0.017及58.11D", "0.017及60.00D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "e5804bd33054", "answer_pdf_sha1": "5a711a9edcd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00465', 'optician', 'optician-moex-112-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '光線從鑽石（折射率2.42）進入空氣，若要形成全反射，其入射角度至少應大於下列何者？', '["10.23度", "24.41度", "33.23度", "42.31度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "e5804bd33054", "answer_pdf_sha1": "5a711a9edcd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00466', 'optician', 'optician-moex-112-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '光在空氣中的傳播速率為300,000km/sec，若光進入一玻璃鏡片傳播速率變為200,000km/sec，則此玻 璃鏡片的折射率應為：', '["1.5", "1.6", "1.67", "1.7"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "e5804bd33054", "answer_pdf_sha1": "5a711a9edcd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00467', 'optician', 'optician-moex-112-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '有一隱形眼鏡片的前曲率半徑和後前曲率半徑均為7.5mm，若中心厚度為0.2mm，折射率為1.490， 則鏡片的後頂點屈光度（backvertexpower）為多少？', '["+0.52D", "+0.54D", "+0.58D", "+0.65D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "e5804bd33054", "answer_pdf_sha1": "5a711a9edcd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00468', 'optician', 'optician-moex-112-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '一名患者的矯正鏡片處方為：OD：+0.25DS/-0.25DC×170、OS：+0.25DS/-0.25DC×010，若其近用加 入度（ADD）為+2.50D，請問當其配製三光鏡片（trifocallens）時，鏡片的中用區加入度（intermediate add）應為多少D（diopter）？', '["+1.00D", "+1.25D", "+1.50D", "+2.00D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "e5804bd33054", "answer_pdf_sha1": "5a711a9edcd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
